sys_script_include.script:
var OrganizationalHierarchyACLs = Class.create();
OrganizationalHierarchyACLs.prototype = {
    initialize: function() {
		this.userInfo = new UserInfoScripts();
	},

	// STRY0138377
	canRead: function (grOU){
		var isUserInGroup = false;

		var userCanRead = false;
		var currentUser = gs.getUserID();
		var isOrgPrivate = grOU.getValue("u_organizational_privacy") == 'private';
		var isUserTaskerApplicationAdmin = this.userInfo.UserHasRole('x_153465_discovert.tasker_application_admin');
		if(!isOrgPrivate || isUserTaskerApplicationAdmin){
			userCanRead=true;
		} else {
			isUserInGroup = this.userInfo.IsUserInOU(grOU.getUniqueValue(),currentUser);
			if(isUserInGroup){
				userCanRead;
			}
		}
		return userCanRead;
	},

	// STRY0138378
	userCanWriteOUPrivacy: function(grOU){
		var answer = false;
		var isExternal = grOU.getValue("u_external_flag")==true;
		var isTopOU = grOU.getValue("parent")=="";
		var isUserOrganizationalAdmin = this.userInfo.UserHasRole('x_153465_discovert.tasker_organizational_admin');
		// If the OU is external, it can only be Open, do not allow the property to change
		if(isExternal || !isTopOU ){
			answer = false;
		} else {
			if(isUserOrganizationalAdmin){
				answer = true;
			} else {
				// new OUs do not have any members, no need to look to see if there is an OU HA
				if(grOU.isNewRecord()){
					answer = false;
				} else {
					answer = this.userInfo.IsUserOUAdministrator(grOU.getUniqueValue(), gs.getUserID());		
				}
			}
		}
		return answer;
	},

	// STRY0138378
	userCanWriteOUisExternal: function(grOU){
		var answer = false;
		var isOrganizationalPrivacyOpen = grOU.getValue("u_organizational_privacy")=='open';
		var isTopOU = grOU.getValue("parent")=="";
		var isUserOrganizationalAdmin = this.userInfo.UserHasRole('x_153465_discovert.tasker_organizational_admin');
		// If the OU is external, it can only be Open, do not allow the property to change
		if(!isOrganizationalPrivacyOpen || !isTopOU){
			answer = false;
		} else {
			if(isUserOrganizationalAdmin){
				answer = true;
			} else {
				// new OUs do not have any members, no need to look to see if there is an OU HA
				if(grOU.isNewRecord()){
					answer = false;
				} else {
					answer = this.userInfo.IsUserOUAdministrator(grOU.getUniqueValue(), gs.getUserID());		
				}
			}
		}
		return answer;
	},

	type: 'OrganizationalHierarchyACLs'
};
